import React, { useState } from "react"
import dot from "../../images/dot.png"
import checkedDot from "../../images/checkeddot.png"
import "../../styles/carousel.scss"

function Carousel({ category, list }) {
  const [imgNumber, setImgNumber] = useState(0)

  const handlePrevImg = e => {
    if (e.type === "keydown" && e.key !== "enter") {
      return
    }

    setImgNumber(prev => {
      if (prev === 0) {
        return (prev = 0)
      }

      return (prev -= 1)
    })
  }

  const handleNextImg = e => {
    if (e.type === "keydown" && e.key !== "Enter") {
      return
    }

    setImgNumber(prev => {
      if (prev === list.length - 1) {
        return (prev = list.length - 1)
      }

      return (prev += 1)
    })
  }

  const handleDot = e => {
    if (e.type === "keydown" && e.key !== "Enter") {
      return
    }

    setImgNumber(Number(e.target.id))
  }

  return (
    <div className={`${category} carousel`}>
      <div className="slider">
        {
          <img
            className="slideImg"
            src={list[imgNumber ?? imgNumber]}
            alt="slide-img"
          />
        }
      </div>

      <div className="buttons">
        <div
          role="button"
          tabIndex={0}
          onKeyDown={handlePrevImg}
          onClick={handlePrevImg}
        >
          <img src="../../arrow.png" alt="prev arrow" className="prev arrow" />
        </div>
        {list.map((el, index) => {
          return (
            <span
              key={el}
              id={index}
              role="button"
              tabIndex={0}
              onKeyDown={handleDot}
              onClick={handleDot}
            >
              <img
                className="dot"
                id={index}
                src={`${imgNumber === index ? checkedDot : dot}`}
                alt="img-select-button"
              />
            </span>
          )
        })}
        <div
          role="button"
          tabIndex={0}
          onKeyDown={handleNextImg}
          onClick={handleNextImg}
        >
          <img src="../../arrow.png" alt="next arrow" className="next arrow" />
        </div>
      </div>
    </div>
  )
}

export default Carousel
